exports.seed = async function (knex) {
  for (const [item_key, langs] of Object.entries(COMBUST_PLANET)) {
    const update = {};
    for (const [lang, f] of Object.entries(langs)) {
      update[`description_${lang}`] = f.description;
      update[`effects_${lang}`] = JSON.stringify(f.effects || []);
    }
    await knex('asta_vakri_library').where({ category: 'combust_planet', item_key }).update(update);
  }
  for (const [h, langs] of Object.entries(COMBUST_HOUSE)) {
    const update = {};
    for (const [lang, txt] of Object.entries(langs)) update[`description_${lang}`] = txt;
    await knex('asta_vakri_library').where({ category: 'combust_house', item_key: `house_${h}` }).update(update);
  }
  for (const [h, langs] of Object.entries(RETRO_HOUSE)) {
    const update = {};
    for (const [lang, txt] of Object.entries(langs)) update[`description_${lang}`] = txt;
    await knex('asta_vakri_library').where({ category: 'retro_house', item_key: `house_${h}` }).update(update);
  }
  // retro_rule + combust_rule share the RULES map; item_key is unique across both.
  for (const [item_key, langs] of Object.entries(RULES)) {
    const update = {};
    for (const [lang, f] of Object.entries(langs)) {
      update[`title_${lang}`] = f.title;
      update[`description_${lang}`] = f.description;
    }
    await knex('asta_vakri_library').whereIn('category', ['retro_rule', 'combust_rule']).where({ item_key }).update(update);
  }
  for (const [item_key, langs] of Object.entries(MISCONCEPTIONS)) {
    const update = {};
    for (const [lang, f] of Object.entries(langs)) {
      update[`title_${lang}`] = f.title;
      update[`description_${lang}`] = f.description;
    }
    await knex('asta_vakri_library').where({ category: 'misconception', item_key }).update(update);
  }
  for (const [item_key, langs] of Object.entries(SPECIAL_REMEDIES)) {
    const update = {};
    for (const [lang, f] of Object.entries(langs)) {
      update[`title_${lang}`] = f.title;
      update[`effects_${lang}`] = JSON.stringify(f.effects || []);
    }
    await knex('asta_vakri_library').where({ category: 'remedy', item_key }).update(update);
  }
};
